const redactMemoryVersion = `UPDATE memory_version SET
    content = NULL,
    redacted_at = now()
WHERE id = $1`

func (q *Queries) RedactMemoryVersion(ctx context.Context, id pgtype.UUID) error {
	_, err := q.db.Exec(ctx, redactMemoryVersion, id)
	return err
}

