const updateVault = `UPDATE vault SET
    display_name = COALESCE(NULLIF($2, ''), display_name),
    metadata = COALESCE($3, metadata),
    updated_at = now()
WHERE id = $1
RETURNING id, workspace_id, display_name, metadata, created_at, updated_at, archived_at`

type UpdateVaultParams struct {
	ID          pgtype.UUID `json:"id"`
	DisplayName string      `json:"display_name"`
	Metadata    []byte      `json:"metadata"`
}

func (q *Queries) UpdateVault(ctx context.Context, arg UpdateVaultParams) (Vault, error) {
	row := q.db.QueryRow(ctx, updateVault, arg.ID, arg.DisplayName, arg.Metadata)
	var i Vault
	err := row.Scan(&i.ID, &i.WorkspaceID, &i.DisplayName, &i.Metadata, &i.CreatedAt, &i.UpdatedAt, &i.ArchivedAt)
	return i, err
}

